macroData.command:
if (args[0]?.macroPass !== "postActiveEffects") return;

// Locate the parent Unarmed Strike item.
const sourceItem =
    workflow.actor?.items.get(workflow.item.id) ??
    workflow.item;

// Locate the Punch activity.
const punch = sourceItem.system.activities.find(activity =>
    activity.identifier === "punch" ||
    activity.name === "Punch"
);

if (!punch) {
    return ui.notifications.error(
        `Flurry of Blows | Could not find the "Punch" activity on ${sourceItem.name}.`
    );
}

// Locate the attacking token.
const sourceToken =
    workflow.token ??
    canvas.tokens.get(workflow.tokenId);

if (!sourceToken) {
    return ui.notifications.error(
        "Flurry of Blows | Could not locate the attacking token."
    );
}

// Preserve the targets selected for Flurry of Blows.
const targets =
    workflow.targets?.size > 0
        ? workflow.targets
        : game.user.targets;

const targetUuids = Array.from(targets)
    .map(target => target.document?.uuid)
    .filter(Boolean);

if (!targetUuids.length) {
    return ui.notifications.warn(
        "Flurry of Blows | Target a creature before using this activity."
    );
}

// Midi-QOL activity-use configuration.
const usage = {
    midiOptions: {
        targetUuids,
        ignoreUserTargets: true,

        configureDialog: false,
        fastForward: true,
        fastForwardAttack: true,
        fastForwardDamage: true,

        autoRollAttack: true,
        autoRollDamage: "onHit",

        workflowOptions: {
            targetConfirmation: "none"
        }
    }
};

const dialog = {
    configure: false
};

const message = {
    systemCard: false
};

// Perform three Punch attacks.
for (let i = 0; i < 3; i++) {

    // Resolve the attack and damage first.
    const punchWorkflow = await MidiQOL.completeActivityUse(
        punch,
        usage,
        dialog,
        message
    );

    // Manually play the Punch Automated Animation.
    if (globalThis.AutomatedAnimations?.playAnimation) {
        await globalThis.AutomatedAnimations.playAnimation(
            sourceToken,
            {
                name: punch.name ?? "Punch"
            },
            {
                targets:
                    punchWorkflow?.targets?.size
                        ? punchWorkflow.targets
                        : targets,

                hitTargets:
                    punchWorkflow?.hitTargets ??
                    new Set(),

                playOnMiss: true
            }
        );
    }
}
